# 1.  Logging (structured, cloud‑ready)
# -------------------------------------------------
logger = logging.getLogger("dispatch")
handler = logging.StreamHandler()
formatter = logging.Formatter(
    '{"timestamp":"%(asctime)s","level":"%(levelname)s","msg":%(message)s}'
)
handler.setFormatter(formatter)
logger.addHandler(handler)
logger.setLevel(logging.INFO)

# -------------------------------------------------
# 2.  Types & validation
# -------------------------------------------------
class LoginArgs(BaseModel):
    username: str = Field(..., min_length=3, max_length=64)
    password: str = Field(..., min_length=8)  # In real life, use OIDC/JWT, not raw passwords


class RetrieveFileArgs(BaseModel):
    file_key: str = Field(..., min_length=1, max_length=1024)

    @validator("file_key")
    def no_path_traversal(cls, v: str) -> str:
        # Disallow ".." segments and absolute paths
        if ".." in v or v.startswith("/"):
            raise ValueError("Invalid file key")
        return v


class ListFilesArgs(BaseModel):
    prefix: str = Field(default="", max_length=256)
    limit: int = Field(default=100, ge=1, le=1000)


# -------------------------------------------------
# 3.  Command handler protocol
# -------------------------------------------------
class CommandHandler(Protocol):
    required_scopes: set[str]

    def validate(self, args: dict[str, Any]) -> BaseModel:
        ...

    def execute(self, user: dict[str, Any], args: BaseModel) -> dict[str, Any]:
        ...


# -------------------------------------------------
# 4.  Helper: simple IAM‑style scope check
# -------------------------------------------------
def has_scopes(user_token: dict[str, Any], required: set[str]) -> bool:
    """Assumes `user_token['scopes']` is a set of granted scopes."""
    return required.issubset(user_token.get("scopes", set()))


# -------------------------------------------------
# 5.  Concrete handlers
# -------------------------------------------------
class LoginHandler:
    required_scopes: set[str] = set()  # No auth needed for login itself

    def validate(self, args: dict[str, Any]) -> LoginArgs:
        return LoginArgs(**args)

    def execute(self, user: dict[str, Any], args: LoginArgs) -> dict[str, Any]:
