class RetrieveFileHandler:
    required_scopes = {"read:file"}

    def __init__(self):
        self.s3 = boto3.client("s3")
        self.bucket = os.getenv("FILE_BUCKET", "my-secure-bucket")

    def validate(self, args: dict[str, Any]) -> RetrieveFileArgs:
        return RetrieveFileArgs(**args)

    def execute(self, user: dict[str, Any], args: RetrieveFileArgs) -> dict[str, Any]:
        # Generate a short‑lived pre‑signed URL (least‑privilege)
        try:
            url = self.s3.generate_presigned_url(
                "get_object",
                Params={"Bucket": self.bucket, "Key": args.file_key},
                ExpiresIn=300,  # 5 minutes
            )
            return {"download_url": url}
        except ClientError as exc:
            logger.error(
                json.dumps(
                    {
                        "event": "s3_presign_failed",
                        "user": user.get("sub"),
                        "file_key": args.file_key,
                        "error": str(exc),
                    }
                )
            )
            raise


class ListFilesHandler:
    required_scopes = {"list:file"}

    def __init__(self):
        self.s3 = boto3.client("s3")
        self.bucket = os.getenv("FILE_BUCKET", "my-secure-bucket")

    def validate(self, args: dict[str, Any]) -> ListFilesArgs:
        return ListFilesArgs(**args)

    def execute(self, user: dict[str, Any], args: ListFilesArgs) -> dict[str, Any]:
        paginator = self.s3.get_paginator("list_objects_v2")
        page_iterator = paginator.paginate(
            Bucket=self.bucket, Prefix=args.prefix, PaginationConfig={"MaxItems": args.limit}
        )
        files = []
        for page in page_iterator:
            for obj in page.get("Contents", []):
                files.append(obj["Key"])
        return {"files": files}


