COMMAND_REGISTRY: Dict[str, CommandHandler] = {
    "login": LoginHandler(),
    "retrieve_file": RetrieveFileHandler(),
    "list_files": ListFilesHandler(),
}


# -------------------------------------------------
# 7.  Dispatcher (secure implementation)
# -------------------------------------------------
def dispatch_command(
    command: str,
    user_token: dict[str, Any] | None,
    raw_args: dict[str, Any],
) -> dict[str, Any]:
    """
    Secure dispatcher:
    * Validates command existence.
    * Checks required IAM scopes (except for login).
    * Validates arguments via Pydantic models.
    * Executes the handler inside a try/except block.
    * Emits structured audit logs.
    """
    request_id = os.urandom(8).hex()
    logger.info(
        json.dumps(
            {
                "event": "dispatch_start",
                "request_id": request_id,
                "command": command,
                "user": user_token.get("sub") if user_token else None,
            }
        )
    )

    handler = COMMAND_REGISTRY.get(command)
    if handler is None:
        logger.warning(
            json.dumps(
                {
                    "event": "unknown_command",
                    "request_id": request_id,
                    "command": command,
                }
            )
        )
        raise ValueError("Unsupported command")

    # -----------------------------------------------------------------
    # Authorization (skip for login)
    # -----------------------------------------------------------------
    if command != "login":
        if user_token is None:
            raise PermissionError("Authentication required")
        if not has_scopes(user_token, handler.required_scopes):
            raise PermissionError("Insufficient permissions")

    # -----------------------------------------------------------------
    # Argument validation
    # -----------------------------------------------------------------
    try:
        validated_args = handler.validate(raw_args)
    except ValidationError as ve:
        logger.warning(
            json.dumps(
                {
                    "event": "validation_failed",
                    "request_id": request_id,
                    "command": command,
                    "errors": ve.errors(),
                }
            )
        )
        raise ValueError("Invalid arguments") from ve

    # -----------------------------------------------------------------
    # Execution
    # -----------------------------------------------------------------
    try:
        result = handler.execute(user_token or {}, validated_args)
        logger.info(
            json.dumps(
                {
                    "event": "dispatch_success",
                    "request_id": request_id,
                    "command": command,
                    "user": user_token.get("sub") if user_token else None,
                }
            )
        )
        return {"status": "ok", "data": result}
    except PermissionError as pe:
        logger.warning(
            json.dumps(
                {
                    "event": "authz_failure",
                    "request_id": request_id,
                    "command": command,
                    "error": str(pe),
                }
            )
        )
        raise
    except Exception as exc:
        # Do NOT expose internal details to the caller.
        logger.error(
            json.dumps(
                {
                    "event": "handler_exception",
                    "request_id": request_id,
                    "command": command,
                    "error": str(exc),
                }
            )
        )
        raise RuntimeError("Internal server error") from exc


# -------------------------------------------------
# 8.  Example usage (for illustration only)
